const mapping = {
  season: { 'forår':'spring','spring':'spring','sommer':'summer','summer':'summer','efterår':'fall','fall':'fall','autumn':'fall','vinter':'winter','winter':'winter' },
  soil_type: { 'sand':'sandy','sandet':'sandy','sandy':'sandy','ler':'clay','lerjord':'clay','clay':'clay','muld':'loamy','muldjord':'loamy','loamy':'loamy','kalk':'chalky','kalkjord':'chalky','chalky':'chalky','tørv':'peaty','tørvejord':'peaty','peaty':'peaty','silt':'silty','siltjord':'silty','silty':'silty' },
  moisture: { 'veldrænet':'well-drained','well-drained':'well-drained','fugtig':'moist but well-drained','moist but well-drained':'moist but well-drained','våd':'poorly drained','poorly drained':'poorly drained' },
};
const body = $input.first().json.body;
return [{ json: {
  season:    mapping.season[   (body.season    || '').toLowerCase()] ?? '',
  soil_type: mapping.soil_type[(body.soil_type || '').toLowerCase()] ?? '',
  moisture:  mapping.moisture[ (body.moisture  || '').toLowerCase()] ?? ''
} }];

const rows = $input.first().json.results?.[0]?.data ?? [];
if (rows.length === 0) return [{ json: { plants: [], message: "Ingen planter matcher betingelserne." } }];
const plants = rows.map(r => ({ name_en: r.row[0], name_da: r.row[1], type: r.row[2], edible: r.row[3] }));
return [{ json: { plants, count: plants.length } }];
